import os
import json
import boto3
from flask import Flask, request, jsonify
from selenium import webdriver
from selenium.webdriver.chrome.service import Service
from selenium.webdriver.chrome.options import Options
from webdriver_manager.chrome import ChromeDriverManager
from botocore.exceptions import NoCredentialsError

app = Flask(__name__)
s3_client = boto3.client('s3', region_name='your-region')

BUCKET_NAME = 'your-s3-bucket-name'

def take_screenshot(url):
    options = Options()
    options.headless = True
    options.add_argument('--no-sandbox')
    options.add_argument('--disable-dev-shm-usage')
    
    driver = webdriver.Chrome(service=Service(ChromeDriverManager().install()), options=options)
    driver.get(url)
    screenshot_path = '/tmp/screenshot.png'
    driver.save_screenshot(screenshot_path)
    driver.quit()
    return screenshot_path

def upload_to_s3(file_path, s3_key):
    try:
        s3_client.upload_file(file_path, BUCKET_NAME, s3_key)
        return f'https://{BUCKET_NAME}.s3.amazonaws.com/{s3_key}'
    except NoCredentialsError:
        return None

@app.route('/screenshot', methods=['POST'])
def screenshot_service():
    data = request.get_json()
    url = data.get('url')
    
    if not url or not isinstance(url, str):
        return jsonify({'error': 'Invalid URL'}), 400

    screenshot_path = take_screenshot(url)
    s3_key = f'screenshots/{url.replace("http://", "").replace("https://", "").replace("/", "_")}.png'
    s3_url = upload_to_s3(screenshot_path, s3_key)

    if s3_url:
        return jsonify({'screenshot_url': s3_url}), 200
    else:
        return jsonify({'error': 'Failed to upload screenshot to S3'}), 500

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=int(os.environ.get('PORT', 5000)))